'use strict';

var values = require('./values.js');

/**
 * Given a text and a msgctxt, returns the translation id.
 *
 * It is using the unicode `\u0004` as prefix because po2json package has this format for context keys.
 * @see {@link https://github.com/melisource/fury_node-i18n-dev-tools/blob/29d968fb0e025fe686dbec36aba19ae1bdf1893a/src/po2json/parse.js#L96 | Parsing code}
 */
const getTranslationId = (text, msgctxt) => typeof msgctxt === 'string' ? `${msgctxt}\u0004${text}` : text;
const REPLACEMENT_REGEX = /\{(\d+)\}/g;
/**
 * Given a text with arguments, replace those arguments in the text.
 *
 * @example
 * replaceArguments('This is {0}, right {0}?', ['John']);
 * // This is John, right John?
 */
const replaceArguments = (text, replacements) => {
    const firstReplacement = replacements[0];
    if (typeof firstReplacement === 'object' &&
        !Array.isArray(firstReplacement)) {
        return values.processTextRecursively(text, firstReplacement);
    }
    const flattenedReplacements = replacements.flat();
    return text.replace(REPLACEMENT_REGEX, (_, index) => `${flattenedReplacements[+index]}`);
};
class I18n {
    #translations;
    #locale;
    #notifyMissingTranslations;
    #notify;
    constructor(options) {
        this.#translations = { ...options.translations }; // Shallow copy to allow additions
        this.#locale = options.locale;
        this.#notifyMissingTranslations =
            options.notifyMissingTranslations ?? false;
        this.#notify = options.notify || function noop() { };
    }
    get locale() {
        return this.#locale;
    }
    get translations() {
        return this.#translations;
    }
    /**
     * Given a text, returns the translation.
     *
     * @example
     * getTranslation('Mi mensaje');
     * // My message
     */
    getTranslation(text, msgctxt) {
        return this.#getTranslation({ key: text, context: msgctxt });
    }
    /**
     * Given a text and a quantity, returns the translation of the text depending on whether it is singular or plural.
     *
     * @example
     * getPluralTranslation('You have {0} message', 'You have {0} messages', 3);
     * // You have 3 messages'
     */
    getPluralTranslation(singularText, pluralText, quantity, context) {
        return this.#getTranslation({
            key: singularText,
            pluralText,
            quantity,
            context,
        });
    }
    /**
     * Given a text, return the translation with its arguments replaced.
     *
     * @param text Text key to search in translations.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * gettext('This is {0}, right {0}?', ['John'])
     * // This is John, right John?
     */
    gettext(text, ...replacements) {
        return replaceArguments(this.getTranslation(text), replacements);
    }
    /**
     * Given a text in singular, a text in plural and a quantity, return the translation with its arguments replaced.
     *
     * @param singularText Singular text key to search in translations.
     * @param pluralText Plural text key to search in translations.
     * @param quantity Number to determine if singular or plural text should be used.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * ngettext('{0}, You have {1} message', '{0}, You have {1} messages', 6, ['John', 6])
     * // John, You have 6 messages
     */
    ngettext(singularText, pluralText, quantity, ...replacements) {
        return replaceArguments(this.getPluralTranslation(singularText, pluralText, quantity), replacements);
    }
    /**
     * Given a context and a text, return the translation with its arguments replaced.
     *
     * @param context The context in which this text will be displayed.
     * @param text Text key to search in translations.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * pgettext('question', This is {0}, right {0}?', ['John'])
     * // This is John, right John?
     */
    pgettext(context, text, ...replacements) {
        return replaceArguments(this.getTranslation(text, context), replacements);
    }
    /**
     * Given a context, a text in singular, a text in plural and a quantity, return the translation with its arguments replaced.
     *
     * @param context The context in which this text will be displayed.
     * @param singularText Singular text key to search in translations.
     * @param pluralText Plural text key to search in translations.
     * @param quantity Number to determine if singular or plural text should be used.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * npgettext('information', {0}, You have {1} message', '{0}, You have {1} messages', 6, ['John', 6])
     * // John, You have 6 messages
     */
    npgettext(context, singularText, pluralText, quantity, ...replacements) {
        return replaceArguments(this.getPluralTranslation(singularText, pluralText, quantity, context), replacements);
    }
    #getTranslation({ key, pluralText, quantity = 1, context, }) {
        const id = getTranslationId(key, context);
        const tr = this.#translations[id];
        let text;
        if (tr) {
            text = quantity === 1 ? tr[1] : tr[2];
        }
        else if (this.#notifyMissingTranslations) {
            this.#notify(key, this.#locale);
        }
        return text ?? (quantity === 1 ? key : pluralText);
    }
}

exports.I18n = I18n;
